import { useEffect, useState } from "react";
import { Plus, Archive, Edit2, Eye, EyeOff } from "lucide-react";
import AdminLayout from "@/layouts/AdminLayout";
import { fetchProducts, createProduct, archiveProduct, updateProduct, fetchShops } from "@/lib/api";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

const emptyProduct = {
    shop_id: "",
    name: "",
    category: "",
    description: "",
    price: 0,
    compare_at_price: null,
    currency: "INR",
    image_url: "",
    hover_image_url: "",
    stock: 0,
    badge: "New",
    is_featured: false,
    is_active: true,
};

export default function AdminProducts() {
    const { adminKey } = useAuth();
    const [products, setProducts] = useState([]);
    const [shops, setShops] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showForm, setShowForm] = useState(false);
    const [isEditing, setIsEditing] = useState(false);
    const [editingId, setEditingId] = useState(null);
    const [formData, setFormData] = useState(emptyProduct);
    const [togglingId, setTogglingId] = useState(null);

    useEffect(() => {
        loadProducts();
        loadShops();
    }, []);

    const loadShops = async () => {
        try {
            const data = await fetchShops({ active_only: true, limit: 500 });
            if (data && Array.isArray(data)) {
                setShops(data);
            } else {
                console.warn("Shops data is not an array:", data);
                setShops([]);
            }
        } catch (error) {
            console.error("Failed to load shops:", error);
            toast.error("Failed to load shops - using empty list");
            setShops([]);
        }
    };

    const loadProducts = async () => {
        try {
            const data = await fetchProducts({ active_only: false, limit: 500 });
            setProducts(data);
        } catch (error) {
            toast.error("Failed to load products");
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (!formData.shop_id) {
                toast.error("Please select a shop");
                return;
            }
            if (!formData.price || formData.price <= 0) {
                toast.error("Price must be greater than 0");
                return;
            }
            if (!formData.image_url) {
                toast.error("Please enter an image URL");
                return;
            }
            if (formData.description.length < 10) {
                toast.error("Description must be at least 10 characters");
                return;
            }

            if (isEditing && editingId) {
                await updateProduct(editingId, formData, adminKey);
                toast.success("Product updated successfully!");
            } else {
                await createProduct(formData, adminKey);
                toast.success("Product created successfully!");
            }
            setShowForm(false);
            setIsEditing(false);
            setEditingId(null);
            setFormData(emptyProduct);
            loadProducts();
        } catch (error) {
            toast.error(error?.response?.data?.detail || "Failed to save product");
        }
    };

    const handleEdit = (product) => {
        setFormData(product);
        setIsEditing(true);
        setEditingId(product.id);
        setShowForm(true);
    };

    const handleCancel = () => {
        setShowForm(false);
        setIsEditing(false);
        setEditingId(null);
        setFormData(emptyProduct);
    };

    const handleArchive = async (productId) => {
        if (!confirm("Archive this product?")) return;
        try {
            await archiveProduct(productId, adminKey);
            toast.success("Product archived");
            loadProducts();
        } catch (error) {
            toast.error("Failed to archive product");
        }
    };

    return (
        <AdminLayout>
            <div>
                <div className="flex items-center justify-between mb-8">
                    <h1 className="text-3xl font-bold">Products</h1>
                    <button
                        onClick={() => {
                            setIsEditing(false);
                            setEditingId(null);
                            setFormData(emptyProduct);
                            setShowForm(!showForm);
                        }}
                        className="flex items-center gap-2 px-4 py-2 bg-maroon text-ivory rounded-lg hover:bg-maroon/90 transition"
                    >
                        <Plus size={20} />
                        Add Product
                    </button>
                </div>

                {/* Form */}
                {showForm && (
                    <form onSubmit={handleSubmit} className="bg-white rounded-lg border border-line-soft p-6 mb-8">
                        <h2 className="text-xl font-bold mb-6">{isEditing ? "Edit Product" : "Create New Product"}</h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {/* Shop Selection */}
                            <div>
                                <label className="block text-sm font-medium mb-2">Shop *</label>
                                <select
                                    value={formData.shop_id}
                                    onChange={(e) => setFormData({ ...formData, shop_id: e.target.value })}
                                    className="w-full px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                                    required
                                >
                                    <option value="">Select a shop</option>
                                    {shops.map((shop) => (
                                        <option key={shop.id} value={shop.id}>
                                            {shop.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            {/* Product Name */}
                            <input
                                type="text"
                                placeholder="Product Name *"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                                required
                            />

                            {/* Category */}
                            <input
                                type="text"
                                placeholder="Category *"
                                value={formData.category}
                                onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                                required
                            />

                            {/* Price */}
                            <input
                                type="number"
                                placeholder="Price *"
                                min="1"
                                value={formData.price}
                                onChange={(e) => setFormData({ ...formData, price: parseInt(e.target.value) || 0 })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                                required
                            />

                            {/* Compare at Price */}
                            <input
                                type="number"
                                placeholder="Compare at Price"
                                min="0"
                                value={formData.compare_at_price || ""}
                                onChange={(e) => setFormData({ ...formData, compare_at_price: e.target.value ? parseInt(e.target.value) : null })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                            />

                            {/* Stock */}
                            <input
                                type="number"
                                placeholder="Stock"
                                min="0"
                                value={formData.stock}
                                onChange={(e) => setFormData({ ...formData, stock: parseInt(e.target.value) || 0 })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                            />

                            {/* Badge */}
                            <input
                                type="text"
                                placeholder="Badge (e.g., New, Sale)"
                                value={formData.badge}
                                onChange={(e) => setFormData({ ...formData, badge: e.target.value })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                            />

                            {/* Image URL */}
                            <input
                                type="text"
                                placeholder="Image URL *"
                                value={formData.image_url}
                                onChange={(e) => setFormData({ ...formData, image_url: e.target.value })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                                required
                            />

                            {/* Hover Image URL */}
                            <input
                                type="text"
                                placeholder="Hover Image URL"
                                value={formData.hover_image_url}
                                onChange={(e) => setFormData({ ...formData, hover_image_url: e.target.value })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none"
                            />

                            {/* Is Featured */}
                            <div className="flex items-center gap-3">
                                <input
                                    type="checkbox"
                                    id="featured"
                                    checked={formData.is_featured}
                                    onChange={(e) => setFormData({ ...formData, is_featured: e.target.checked })}
                                    className="w-4 h-4 cursor-pointer"
                                />
                                <label htmlFor="featured" className="cursor-pointer">Featured Product</label>
                            </div>

                            {/* Description */}
                            <textarea
                                placeholder="Description (min 10 characters) *"
                                value={formData.description}
                                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                className="px-4 py-2 border border-line-soft rounded-lg focus:border-maroon outline-none md:col-span-2"
                                rows="4"
                                required
                            />
                        </div>
                        <div className="flex gap-4 mt-6">
                            <button
                                type="submit"
                                className="px-6 py-2 bg-maroon text-ivory rounded-lg hover:bg-maroon/90 transition"
                            >
                                {isEditing ? "Update Product" : "Create Product"}
                            </button>
                            <button
                                type="button"
                                onClick={handleCancel}
                                className="px-6 py-2 border border-line-soft rounded-lg hover:bg-gray-50 transition"
                            >
                                Cancel
                            </button>
                        </div>
                    </form>
                )}

                {/* Products Table */}
                {loading ? (
                    <div className="flex items-center justify-center h-64">
                        <p className="text-espresso/60">Loading products...</p>
                    </div>
                ) : (
                    <div className="bg-white rounded-lg border border-line-soft overflow-hidden">
                        <table className="w-full">
                            <thead className="bg-gray-50 border-b border-line-soft">
                                <tr>
                                    <th className="px-6 py-4 text-left text-sm font-semibold">Name</th>
                                    <th className="px-6 py-4 text-left text-sm font-semibold">Shop</th>
                                    <th className="px-6 py-4 text-left text-sm font-semibold">Category</th>
                                    <th className="px-6 py-4 text-left text-sm font-semibold">Price</th>
                                    <th className="px-6 py-4 text-left text-sm font-semibold">Stock</th>
                                    <th className="px-6 py-4 text-left text-sm font-semibold">Status</th>
                                    <th className="px-6 py-4 text-right text-sm font-semibold">Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {products.map((product) => (
                                    <tr key={product.id} className="border-b border-line-soft hover:bg-gray-50">
                                        <td className="px-6 py-4 text-sm">{product.name}</td>
                                        <td className="px-6 py-4 text-sm text-espresso/60">{product.shop_name || "N/A"}</td>
                                        <td className="px-6 py-4 text-sm text-espresso/60">{product.category}</td>
                                        <td className="px-6 py-4 text-sm font-medium">
                                            {product.currency} {product.price}
                                        </td>
                                        <td className="px-6 py-4 text-sm">{product.stock}</td>
                                        <td className="px-6 py-4 text-sm">
                                            <span
                                                className={`px-3 py-1 rounded-full text-xs font-medium ${
                                                    product.is_active
                                                        ? "bg-green-100 text-green-700"
                                                        : "bg-gray-100 text-gray-700"
                                                }`}
                                            >
                                                {product.is_active ? "Active" : "Archived"}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex items-center justify-end gap-3">
                                                <button
                                                    onClick={() => handleEdit(product)}
                                                    className="text-blue-600 hover:text-blue-700 transition"
                                                >
                                                    <Edit2 size={18} />
                                                </button>
                                                <button
                                                    onClick={() => handleArchive(product.id)}
                                                    className="text-maroon hover:text-maroon/70 transition"
                                                >
                                                    <Archive size={18} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </AdminLayout>
    );
}
